import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Testimonials.css';

const Testimonials = () => {
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTestimonials = async () => {
      try {
        const response = await axios.get('/api/testimonials');
        setTestimonials(response.data.testimonials);
        setLoading(false);
      } catch (error) {
        console.error('Error fetching testimonials:', error);
        // Fallback testimonials if API fails
        setTestimonials([
          {
            id: 1,
            name: "Sarah Johnson",
            company: "Tech Solutions Ltd",
            text: "Greyline Accountants Ltd. has been instrumental in helping us manage our finances. Their expertise and attention to detail are outstanding.",
            rating: 5
          },
          {
            id: 2,
            name: "Michael Chen",
            company: "Digital Marketing Agency",
            text: "Professional, reliable, and always available when we need them. Highly recommend Greyline Accountants Ltd. for any business.",
            rating: 5
          },
          {
            id: 3,
            name: "Emma Williams",
            company: "Creative Studio",
            text: "The team at Greyline Accountants Ltd. made our tax returns stress-free. They're knowledgeable and always explain everything clearly.",
            rating: 5
          }
        ]);
        setLoading(false);
      }
    };

    fetchTestimonials();
  }, []);

  if (loading) {
    return (
      <section id="testimonials" className="testimonials">
        <div className="container">
          <div className="loading">Loading testimonials...</div>
        </div>
      </section>
    );
  }

  return (
    <section id="testimonials" className="testimonials">
      <div className="container">
        <div className="section-header">
          <h2 className="section-title">What Our Clients Say</h2>
          <p className="section-subtitle">
            Don't just take our word for it - hear from our satisfied clients
          </p>
        </div>

        <div className="testimonials-grid">
          {testimonials.map((testimonial) => (
            <div key={testimonial.id} className="testimonial-card">
              <div className="testimonial-rating">
                {[...Array(testimonial.rating)].map((_, i) => (
                  <span key={i} className="star">★</span>
                ))}
              </div>
              <p className="testimonial-text">"{testimonial.text}"</p>
              <div className="testimonial-author">
                <strong>{testimonial.name}</strong>
                <span>{testimonial.company}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Testimonials;
